const sendgrid = require('@sendgrid/mail');
const twilio = require('twilio');
const functions = require('firebase-functions');
require("dotenv").config();  // to load env variables from .env file

// Initialize SendGrid with your API Key
sendgrid.setApiKey(process.env.SENDGRID_API_KEY);

// Initialize Twilio with your Account SID and Auth Token
twilio.init(process.env.TWILIO_ACCOUNT_SID, process.env.TWILIO_AUTH_TOKEN);

exports.sendEmailAndText = functions.https.onRequest((req, res) => {
  // Extract email and text from request body
  const {email, text} = req.body;
  
  if (!email || !text) {
    return res.status(400).send('Missing required fields: email or text');
  }

  // Send an email using SendGrid
  sendgrid.send({
    to: email,
    from: 'your-email@example.com',   // replace with your verified sender email
    subject: 'Your Subject',            // customize as per requirement
    text: text                          // the message content
  })
  .then(() => {
    console.log('Email sent!');
    
    // Send a SMS using Twilio
    twilio.messages.create({
      to: 'recipient-phone-number',   // replace with recipient phone number
      from: 'your-twilio-phone-number',  // replace with your Twilio phone number
      body: text                        // the message content
    })
    .then(() => {
      console.log('Text sent!');
      
      res.status(200).send({message: 'Email and SMS sent successfully'});
    })
    .catch((error) => {
      console<｜begin▁of▁sentence｜>crape.log(`Error sending SMS: ${error}`);
      
      // If there was an error with the Twilio request, send a 500 response
      res.status(500).send({message: 'Failed to send SMS', error});
    });
  })
  .catch((error) => {
    console.log(`Error sending email: ${error}`);
    
    // If there was an error with the SendGrid request, send a 500 response
    res.status(500).send({message: 'Failed to send email', error});
  });
});